+fn explicit_config_gear_names(config_path: &Path) -> Result<HashSet<String>> {
+    let raw = std::fs::read_to_string(config_path)?;
+    let json: serde_json::Value = strict_yaml_parse(&raw)
+        .with_context(|| format!("failed to parse config file: {}", config_path.display()))?;
+
+    Ok(json
+        .get("gears")
+        .and_then(serde_json::Value::as_object)
+        .map(|gears| gears.keys().cloned().collect())
+        .unwrap_or_default())
+}
+
+fn explicit_gear_file_names(dir: impl AsRef<Path>) -> Result<HashSet<String>> {
+    use std::fs;
+
+    let dir = dir.as_ref();
+    if !dir.exists() {
+        return Ok(HashSet::new());
+    }
+
+    let mut names = HashSet::new();
+    for entry in fs::read_dir(dir)? {
+        let entry = entry?;
+        let path = entry.path();
+        if !path.is_file() {
+            continue;
+        }
+        let ext = path
+            .extension()
+            .and_then(|s| s.to_str())
+            .unwrap_or("")
+            .to_ascii_lowercase();
+        if ext != "yml" && ext != "yaml" {
+            continue;
+        }
+        if let Some(name) = path.file_stem().and_then(|s| s.to_str()) {
+            names.insert(name.to_owned());
+        }
+    }
+    Ok(names)
+}
+
+fn reconcile_kubernetes_safe_gear_aliases(
+    gears: &mut HashMap<String, serde_json::Value>,
+    explicit_gear_names: &HashSet<String>,
+) {
+    let aliases = gears
+        .keys()
+        .filter(|name| name.contains('-'))
+        .map(|name| (name.clone(), name.replace('-', "_")))
+        .collect::<Vec<_>>();
+
+    for (dashed_name, alias) in aliases {
+        if explicit_gear_names.contains(&alias) {
+            continue;
+        }
+
+        let Some(alias_value) = gears.remove(&alias) else {
+            continue;
+        };
+
+        if let Some(dashed_value) = gears.get_mut(&dashed_name) {
+            merge_json_values(dashed_value, &alias_value);
+        } else {
+            gears.insert(alias, alias_value);
+        }
+    }
+}
+
+fn merge_json_values(target: &mut serde_json::Value, source: &serde_json::Value) {
+    if let (Some(target_obj), Some(source_obj)) = (target.as_object_mut(), source.as_object()) {
+        for (key, value) in source_obj {
+            if let Some(target_value) = target_obj.get_mut(key) {
+                if target_value.is_object() && value.is_object() {
+                    merge_json_values(target_value, value);
+                } else {
+                    *target_value = value.clone();
+                }
+            } else {
+                target_obj.insert(key.clone(), value.clone());
+            }
+        }
+    } else {
+        *target = source.clone();
+    }
+}
